var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"……확실히 강력하군요.","JPN":"……確かに手強い相手ですね。","ENG":"…He sure is strong, just as I expected.","TWN":"……確實滿強的！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"지금도 저 정도의 힘을 뿜어내는 걸 보면 완성된 후에는 훨씬 더 귀찮아질 겁니다.","JPN":"今でもあれほどの力を出せる以上、完成した後はもっと厄介になるでしょう。","ENG":"If he's that strong already, he'll be a real pain in the neck once he's completed.","TWN":"半成品就已經可以發揮如此強的力量，完成後會更難對付！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그럴 바에는 차라리 여기서 처치하는 게 좋지 않을까요?","JPN":"それならいっそここで退治した方がいいんじゃないですか？","ENG":"Why don't we just take it out now?","TWN":"與其這樣，倒不如現在就將他斬草除根吧？"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"나유빈! 너 무슨 소릴 하는 거야?","JPN":"イチノセ！　あなた、何を言っているの？","ENG":"Yubin! What are you talking about?","TWN":"羅瑜斌！你在說什麼！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 녀석은 내 사원이라고! 함부로 손대는 건 용납 못해!","JPN":"あの子はうちの社員よ！　勝手に手を出すのは許さないわ！","ENG":"He's my employee! I won't let you hurt him!","TWN":"他可是我的員工！你如果敢對他出手我絕不饒你！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만 수연아, 너도 알고 있잖아.","JPN":"でもキズナ、君も知ってるだろ？","ENG":"But you get it too, don't you?","TWN":"秀妍你應該聽過這句話吧？"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"계획을 세우는 입장에서 변수는 그리 환영할 만한 존재가 아니라는 걸.","JPN":"計画を立てる立場として、不確定要素はあまり歓迎すべき存在ではないということを。","ENG":"When it comes to planning, nobody likes a variable.","TWN":"所謂計畫趕不上變化。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그건 스승님도 마찬가지일 테고요.","JPN":"それは師匠も同じでしょう。","ENG":"I'm sure you feel the same way, Master.","TWN":"師父應該也認同吧？"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……말했을 텐데.","JPN":"……言ったはずだ。","ENG":"…Have I not made it clear?","TWN":"……我說過了，"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"우린 여기에 주시윤을 구출하기 위해 온 거다.","JPN":"私たちはアキヤマを救出するためにここに来た。","ENG":"We are here to save Joo Shiyoon.","TWN":"我們來這裡是要救周時雲。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"나와 함께 행동할 생각이라면 내 지휘를 따라라, 나유빈.","JPN":"私と一緒に行動するつもりなら私の指揮に従え、イチノセ。","ENG":"If you wish to stay with me, you will submit to my command, Na Yubin.","TWN":"你想和我一起行動的話就乖乖聽我的指揮，羅瑜斌！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"너, 루크레시아라고 했던가?","JPN":"お前、ルクレシアと言ったか？","ENG":"You. Lucrecia, was it?","TWN":"你叫露可蕾西亞？"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……그렇습니다만.","JPN":"……そうですが。","ENG":"…Aye.","TWN":"……是沒錯。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"이쯤에서 끝내고 돌아가라.","JPN":"この辺にして帰れ。","ENG":"Just call it day and go.","TWN":"到此為止，你們回去吧！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"최초의 용혈로 제련한 용인이라고 해도, 지금 우리 둘을 상대로는 승산이 없어.","JPN":"原初の龍血で製錬した龍人でも、今の私たち2人を相手に勝算はない。","ENG":"You stand no chance against the two of us, even if you've forged that Dragonoid from the first Dragon Blood.","TWN":"就算他是用原始的龍血煉製而成的龍人，以他目前的能力是打不贏我們的。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"이대로 계속 싸워 봤자 그 미완성의 용인만 잃을 뿐이다.","JPN":"このまま戦い続けたところで、その未完成の龍人を失うだけだ。","ENG":"If you keep fighting, you'll only lose your unfinished Dragonoid.","TWN":"再打下去，結果就是你會失去那個半成品的龍人。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"결국……. 당신도 제자의 목숨은 아깝다는 거군요.","JPN":"結局……あなたも弟子の命は手放せないのですね。","ENG":"So… You value your apprentice's life in the end.","TWN":"說到底……你也是會擔心徒弟的性命的。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"피도 눈물도 없는 전사라던 발키리에 어울리지 않는 판단이네요.","JPN":"血も涙もない戦士と呼ばれるヴァルキリーにはふさわしくない判断ですね。","ENG":"That's not what I expected from a heartless warrior like a Valkyrie.","TWN":"你的這個決定完全不符合女武神沒血沒淚的人設呢。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"돌아가라고 했나요? 미안하지만 싫습니다.","JPN":"帰れと言いましたか？　申し訳ありませんが、お断りします。","ENG":"You bade me to leave? Forgive me, but I must decline.","TWN":"你要我回去？很抱歉，我拒絕。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"무슨 뜻이지? 저 용인을 잃어도 된다는 건가?","JPN":"どういう意味だ？　あの龍人を失ってもいいってことか？","ENG":"Why? Would you rather risk losing the Dragonoid?","TWN":"什麼意思？失去龍人你也無所謂嗎？"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"용인을 잃더라도 우리의 계획에는 큰 지장이 없습니다. 시기가 조금 늦어질 뿐이죠.","JPN":"龍人を失っても私たちの計画には大きな支障はありません。時期が少し遅れるだけです。","ENG":"Even should the Dragonoid perish, it will not significantly hamper our plans. It will merely delay them a little.","TWN":"失去龍人對我們的計畫不會有太大的影響，頂多就是稍微延後而已。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"중요한 것은……. 당신을 상처 입히고 고통 속에서 몸부림치게 만드는 겁니다.","JPN":"大事なことは……あなたを傷つけ苦痛の中に身を沈めさせることです。","ENG":"What's really important… is that I wound you and make you writhe in agony.","TWN":"更重要的是……折磨你，讓你在痛苦中掙扎。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그래요. 당신의 손으로 당신의 제자를 죽이게 만드는 것도 꽤 재미있을 것 같군요.","JPN":"そうですね。自身の手で弟子を殺させるのも、とても面白そうですね。","ENG":"Indeed. It will be most amusing to watch you kill your own apprentice.","TWN":"所以囉，讓你親手殺掉你的徒弟應該會滿有意思的。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그렇게 해서 우리가 느낀 절망의 일부라도 당신에게 맛보여 줄 수 있다면.","JPN":"そうして私たちが感じた絶望を、少しでもあなたに味わってもらえるなら。","ENG":"I only hope that will make you feel a modicum of the despair you've brought upon us.","TWN":"讓你體會到和我們一樣的絕望，就算只有萬分一之也好！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"너……!","JPN":"お前……！","ENG":"You…!","TWN":"你……！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"최초의 용인이여, 너의 주인이 명한다.","JPN":"原初の龍人よ、お前の主が命じる。","ENG":"Firstborn of Dragonoids, thy master commands thee.","TWN":"原始的龍人聽命！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이 자리에서 생명이 다할 때까지…… ","JPN":"この場で命が尽きるまで……","ENG":"Till all life here expires… ","TWN":"我命令你在這裡直到耗盡生命為止…… "},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"돌아와라. 루크레시아.","JPN":"戻れ、ルクレシア。","ENG":"Come back, Lucrecia.","TWN":"露可蕾西亞，你回來吧！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……이제 와서 무슨 말씀이시죠, 전하.","JPN":"……今更何を言っているのですか、殿下。","ENG":"…Don't you think it's too late for that, Your Highness?","TWN":"……殿下，您這是什麼意思？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"성역 강림지의 수호는 본래 전하가 맡았어야 할 일입니다.","JPN":"聖域降臨の地の守護は本来殿下が担うべきことでした。","ENG":"Safeguarding the sanctuary's spawning ground was originally your responsibility.","TWN":"守護聖域再臨地本來是您的責任，"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하찮은 일이라는 이유로 지금까지 방관만 하던 주제에 이제 와서 물러나라니요?","JPN":"つまらないなどという理由で今まで傍観していたくせに、今更引き下がれと言うのですか？","ENG":"A responsibility you evaded, as you found it beneath you till now… And now you wish me to retreat?","TWN":"但您不想管就一直袖手旁觀，現在卻要我回去？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"……벌써 오늘만 세 번째로군.","JPN":"……今日だけでもう3回目だな。","ENG":"…That's the third time today.","TWN":"……你今天已經犯第三次了。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"황족을 능멸하는 행위를 눈감아주는 것도 여기까지다.","JPN":"皇族を侮辱する行為に目をつぶってやるのもここまでだ。","ENG":"I will no longer tolerate any more of your insolence.","TWN":"我不會再容忍你藐視皇族的的言行！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"노예라면 노예답게, 잠자코 명령에 따라라.","JPN":"奴隷なら奴隷らしく、黙って命令に従え。","ENG":"Submit and obey like the slave you are.","TWN":"身為奴隸就給我好好當奴隸！你只要聽命行事就好！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"거절하겠습니다. 납득할 만한 이유가 없다면……","JPN":"お断りします。納得できる理由がなければ……","ENG":"I refuse. If you will not give me an acceptable reason…","TWN":"如果沒有充分的理由，請恕我拒絕……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>늑대</color>가 이곳에 들어왔다.","JPN":"<color=#ffd34c>狼</color>がここに入ってきた。","ENG":"The <color=#ffd34c>Wolf</color> is here.","TWN":"<color=#ffd34c>狼</color>回到這裡了。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……뭐라고요?","JPN":"……なんですって？","ENG":"…What did you say?","TWN":"……什麼？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"아무것도 몰랐다는 듯이 말하지 마라. 나를 바보로 여기는 것 같아 불쾌하니까.","JPN":"とぼけるな。私を馬鹿にしているようで不快極まりない。","ENG":"Do not feign ignorance with me. The very notion you'd take me for a fool brings me great displeasure.","TWN":"你少一副不知情的樣子，你真當我是笨蛋嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"아무리 저주받은 늑대라고 해도 갑자기 이곳에 나타날 수는 없지.","JPN":"いくら呪われた狼だとしても、突然ここに現れることはできない。","ENG":"Even the Cursed Wolf couldn't possibly just appear here so suddenly.","TWN":"就算是受詛咒的狼，也無法突然就出現在這裡，"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"누군가가 흔적을 남겨 늑대를 이곳으로 유인한 것이 아니라면 말이야.","JPN":"誰かが痕跡を残して、狼をここに誘引したのでなければ。","ENG":"Someone must have left a trail for the Wolf to sniff.","TWN":"一定是有人留下線索把狼引到這裡的！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그 평민 놈이 늑대에겐 아직 손을 대지 말라고 당부했을 텐데?","JPN":"あの平民に狼にはまだ手を出すなと言われたはずだが。","ENG":"Didn't the peasant tell you to leave the Wolf alone for now?","TWN":"那個死老百姓應該有吩咐過暫且不要對狼出手吧？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"잘난 구원자님 말이라면 심장이라도 내놓을 듯이 굴더니, 뒷구멍으로는 꽤나 재밌는 계획을 꾸미고 있었지 않느냐?","JPN":"貴様の尊い救世主様の命令なら心臓すら差し出しそうな\\n振舞いをしていたくせに、裏では面白い計画を立てていたようだな。","ENG":"You behave as if you'd surrender your own heart for your blessed Savior, yet you've been plotting the most amusing scheme in the shadows, have you not?","TWN":"對著救贖者大人裝作一副誓死效忠的樣子，私底下卻另有企圖不是嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"후후, 처음으로 네 천박한 짓거리가 마음에 들기 시작했다.","JPN":"フフッ、貴様の卑しい行動が気に入ったのは初めてだ。","ENG":"Haha… For the first time, I rather fancy your vulgar machinations.","TWN":"呵呵～我還是第一次對你卑鄙的勾當感興趣呢。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이번만은 네 각본에 맞춰 놀아 주마.","JPN":"今回だけは貴様の脚本どおりに演じてやる。","ENG":"I shall play along with your schemes for now.","TWN":"所以這次就姑且配合你的劇本演出吧！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그러니 내 마음이 변하기 전에 돌아오도록.","JPN":"だから私の気が変わる前に戻ってくるように。","ENG":"Now get back here before I change my mind.","TWN":"趁我還沒改變心意之前，你最好趕快回來！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"알겠…… 습니다.","JPN":"承知……しました。","ENG":"Very… well…","TWN":"是……遵命。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"지금 돌아가도록 하죠.","JPN":"今すぐ戻ります。","ENG":"I shall return this moment.","TWN":"我立刻回去。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……사라졌군.","JPN":"……消えたか。","ENG":"…She's gone.","TWN":"……消失了。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"성역화가 진행 중인 곳에선 공간도 마음대로 조작할 수 있는 건가?","JPN":"聖域化が進んでいる場所では空間も自由に操作できるのか？","ENG":"So, they can manipulate space even in a sanctified space?","TWN":"這是在聖域化進行的地方也可以隨意操控空間的意思嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"안에서는 외부와의 통신도 끊어질 가능성이 크겠군. 정면에서 싸우면 귀찮아지겠어.","JPN":"中では外部との通信も切れる可能性が高いな。正面から戦ったら面倒になりそうだ。","ENG":"It's likely we'll lose comms once we get in there. A frontal assault could get tricky.","TWN":"那內外的通訊很可能也會斷掉，這樣正面交手會很棘手。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"……스승님.","JPN":"……師匠。","ENG":"Master...","TWN":"……師父。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"뭐지. 대화를 나누기엔 시간이 넉넉하지 않아.","JPN":"何だ。おしゃべりをする時間の余裕はない。","ENG":"What is it. We don't have much time for chitchat.","TWN":"幹嘛？你有話就快說！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"멍청한 제자 놈을 구하려면 바로 쫓아가야 한다.","JPN":"間抜けな弟子を救うにはすぐに追いかけねば。","ENG":"We must go after them now, if we want to save my stupid apprentice.","TWN":"現在必須趕快追上去才能把人救出來。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이건 스승님답지 않습니다.","JPN":"これは師匠らしくありません。","ENG":"This isn't like you, Master.","TWN":"這樣一點也不像師父。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"뭐? 무슨 뜻이지?","JPN":"は？　どういう意味だ？","ENG":"What? What do you mean?","TWN":"什麼意思？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"전 스승님을 이해하고 있습니다.","JPN":"僕は師匠を理解しています。","ENG":"Listen, I get you, Master.","TWN":"我很清楚師父是什麼樣的人。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"몇 번이고 말씀드릴 수 있습니다. 관리실패 때, 스승님이 저와 수연이를 버리고 떠난 것도 원망하지 않아요.","JPN":"何度でも申し上げられます。管理失敗の時、師匠が僕とキズナを置き去りにしたことも恨んでいません。","ENG":"I'll say this as many times as you want. I don't blame you for abandoning me and Sooyeon when the Administration Failure took place.","TWN":"要我說幾次都可以，對於管理失敗時師父拋下我和秀妍的事，我真的沒有任何埋怨。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그건, 스승님이 해야 할 일을 하기 위해 떠나셨기 때문입니다.","JPN":"それは、師匠がなすべきことをするために立ち去ったからです。","ENG":"You simply did what you had to do.","TWN":"師父是因為要顧全大局才拋下我們離開。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"……어떤 희생을 감수하더라도 말이죠.","JPN":"……どんな犠牲を払ってでも。","ENG":"…No matter the cost.","TWN":"……明明知道會有所犧牲也必須這麼做。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그래서 수연이를 남겨둔 겁니다.","JPN":"それでキズナを残しておいたのです。","ENG":"That's why I left Sooyeon behind.","TWN":"所以我才會把秀妍留在師父身邊。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"힘든 선택을 해야만 하는 당신이, 조금이나마 쉴 수 있게요.","JPN":"辛い選択をしなければならないあなたが、少しでも休めるように。","ENG":"That was the only way you could make peace with that very difficult choice.","TWN":"有秀妍在，至少師父心裡會比較輕鬆。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"절 실망시키지 마세요, 스승님.","JPN":"僕を失望させないでください、師匠。","ENG":"Don't disappoint me like this, Master.","TWN":"師父，請不要讓我失望。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"감정에 휘둘리는 건 스승님의 일이 아닙니다. 스승님은 세상을 위해…….","JPN":"感情に振り回されるのは師匠のなすべきことではありません。師匠は世界のために……","ENG":"It's not your job to let your emotions get the better of you. You're meant to serve the world by…","TWN":"師父不是感情用事的人，師父的責任是守護世界……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"시끄럽다, 나유빈.","JPN":"うるさい、イチノセ。","ENG":"Shut it, Yubin.","TWN":"你閉嘴，羅瑜斌。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"구 관리국의 비밀기록을 조금 봤다고 해서 나에 대해 전부 아는 것처럼 이야기 하지 마라.","JPN":"旧管理局の秘密記録を少し見たからって、私について全部知ったように話すな。","ENG":"Don't speak as if you know everything about me just because you took a peek at the Old Administration's classified files.","TWN":"不要以為你有看過舊管理局的機密檔案，就好像知道我的全部一樣。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"내가 하는 일이, 바로 내가 해야 할 일이다.","JPN":"私がすることが、私のなすべきことだ。","ENG":"I do what I must do.","TWN":"我所做的就是我該做的。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그리고 네가 날 어떻게 생각하든, 난 내가 해야 할 일을 할 뿐이다.","JPN":"そしてお前が私をどう思おうが、私は自分のなすべきことをするだけだ。","ENG":"And no matter what you think of me, I do what I must.","TWN":"還有，無論你怎麼看我，我只做我該做的事。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"방금 네가 말했던 것처럼.","JPN":"さっきお前が言ったようにな。","ENG":"Just like you said.","TWN":"就像你剛才說的一樣！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"시간을 너무 지체했군.","JPN":"のんびりしすぎたようだ。","ENG":"We've wasted too much time.","TWN":"沒時間了！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"여기까지 온 이상 <color=#ffd34c>조력자</color>한테 안내 받을 필요는 없겠지.","JPN":"ここまで来た以上、<color=#ffd34c>協力者</color>に案内してもらう必要はないだろう。","ENG":"I won't need an <color=#ffd34c>asset</color> to guide me now that I've come so far.","TWN":"現在這個情況已經不需要<color=#ffd34c>小幫手</color>帶路了。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"난 먼저 가겠다. 따라오든 말든 마음대로 해라.","JPN":"私は先に行く。ついて来るかどうかは勝手にしろ。","ENG":"I'm going to go ahead. You can follow me or not. It's up to you.","TWN":"我先走了，你來不來隨便你！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};